form:Form.form:Scripts:
		function confirmGuardar()
{   
	if (Ctrl('main').GetMode()=="NEW")
	{                     
	var param="<PARAM oi_empresa='"+Ctrl("oi_empresa").GetXValue()+"' oi_puesto='"+Ctrl("oi_puesto").GetXValue()+"' c_posicion='"+Ctrl("c_posicion").GetXValue()+"' />";
	var np = new NomadProxy("", ut);
	var nSQL = np.SQLService();
	var result = nSQL.GetOBJ(Ctrl("main").getResource("qry:POSICION_EXISTENTE"), param);   
		if (result.flag=="1")
			return confirm("Esta posición ya esta creada. ¿Esta seguro que desea modificar sus datos?");   
		else
			return true; 
	}   	
	return true;
}
